const body = $input.first().json.body;

let message = '';
let from = '';
let timestamp = '';

if (body.Body && body.From) {
  message = body.Body;
  from = body.From;
  timestamp = body.MessageSid || new Date().toISOString();
} else if (body.entry && body.entry[0] && body.entry[0].changes) {
  const change = body.entry[0].changes[0];
  if (change.value && change.value.messages && change.value.messages[0]) {
    const msg = change.value.messages[0];
    message = msg.text?.body || '';
    from = msg.from || '';
    timestamp = new Date().toISOString();
  }
} else {
  message = typeof body === 'string' ? body : JSON.stringify(body);
  from = 'unknown';
  timestamp = new Date().toISOString();
}

function extractRepoName(msg) {
  if (!msg) return null;
  const patterns = [
    /(?:in|to|for|create)\s+(?:repo|repository|project)\s+([a-zA-Z0-9_-]+)/i,
    /(?:repo|repository|project)\s+([a-zA-Z0-9_-]+)/i,
  ];
  for (const p of patterns) {
    const m = msg.match(p);
    if (m) return m[1].toLowerCase().replace(/[^a-z0-9_-]/g, '-');
  }
  return null;
}

function extractAction(msg) {
  if (!msg) return 'build';
  const l = msg.toLowerCase();
  if (l.includes('fix') || l.includes('bug')) return 'fix';
  if (l.includes('scaffold') || l.includes('init')) return 'scaffold';
  if (l.includes('refactor')) return 'refactor';
  if (l.includes('test')) return 'test';
  if (l.includes('deploy')) return 'deploy';
  return 'build';
}

const repoName = extractRepoName(message);

return [{
  json: {
    task: message,
    from,
    timestamp,
    repoName: repoName || `auto-project-${Date.now()}`,
    action: extractAction(message),
    safeRepoName: (repoName || `project-${Date.now()}`).replace(/[^a-zA-Z0-9_-]/g, '')
  }
}];

const FORBIDDEN = [
  /\brm\s+-rf\s+\//i,
  /\bdrop\s+table\b/i,
  /\bdrop\s+database\b/i,
  /\bforce\s+push\b.*\bmain\b/i,
  /\bgit\s+push\s+--force\b.*\b(main|master)\b/i,
  /\bsudo\b/i,
  /\bchmod\s+777\b/i,
  /\bcurl\b.*\|\s*bash\b/i,
];

const DANGEROUS = ['delete production','drop production','wipe database','destroy','nuke','rm -rf'];
const task = ($input.first().json.task || '').toLowerCase();

for (const p of FORBIDDEN) {
  if (p.test(task)) {
    return [{ json: { safe: false, reason: `Blocked: ${p.source}`, requiresConfirmation: false, task: $input.first().json.task } }];
  }
}

for (const kw of DANGEROUS) {
  if (task.includes(kw)) {
    return [{ json: { safe: false, reason: `Dangerous keyword: ${kw}`, requiresConfirmation: true, task: $input.first().json.task } }];
  }
}

return [{ json: { safe: true, reason: 'Passed', requiresConfirmation: false, task: $input.first().json.task } }];

